INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('actual-loss', 'silbi-claim-documents', '실손보험 청구 서류 총정리 — 무엇을 어떻게 준비할까', '실손의료비 청구에 필요한 서류를 외래·입원·약제비로 나눠 정리하고, 소액 청구 간소화와 전자청구 방법까지 한눈에 안내합니다.', '<p>실손의료비보험은 실제 부담한 의료비를 보장하는 상품이라, 청구 시 "얼마를 어디에 썼는지"를 증빙하는 서류가 핵심입니다. 서류가 빠지면 심사가 지연되므로 미리 구분해 챙기는 것이 좋습니다.</p>
<h2>기본 공통 서류</h2>
<ul>
<li>보험금 청구서 (보험사 양식, 모바일 앱으로 대체 가능)</li>
<li>신분증 사본 또는 본인 확인</li>
<li>보험금 받을 본인 명의 통장 사본</li>
</ul>
<h2>진료 형태별 추가 서류</h2>
<table>
<thead><tr><th>구분</th><th>필요 서류</th></tr></thead>
<tbody>
<tr><td>외래(통원)</td><td>진료비 영수증, 진료비 세부내역서, (필요시) 통원확인서·진단서</td></tr>
<tr><td>입원</td><td>입·퇴원확인서 또는 진단서, 진료비 영수증, 진료비 세부내역서</td></tr>
<tr><td>약제비</td><td>약제비 영수증, 처방전</td></tr>
</tbody>
</table>
<h2>소액 청구는 간소화</h2>
<p>대부분의 보험사는 일정 금액(흔히 외래 건당 소액) 이하일 때 진단서 없이 영수증과 세부내역서만으로 청구를 받습니다. 금액이 커지거나 질병명이 필요한 경우에는 진단서를 요구할 수 있습니다.</p>
<h2>모바일·전자청구 활용</h2>
<p>최근에는 병원에서 발급받은 서류를 사진으로 찍어 보험사 앱에 올리면 청구가 끝나는 경우가 많습니다. 일부 의료기관은 진료비 정보를 보험사로 바로 전송하는 실손 청구 간소화 서비스도 제공합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>영수증·세부내역서는 거의 항상 필요</li><li>금액이 크면 진단서 준비</li><li>청구권 소멸시효는 3년 — 미루지 말 것</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["실손보험","보험금청구","청구서류"]', '[{"q":"실손보험 청구 기한이 있나요?","a":"보험금청구권의 소멸시효는 원칙적으로 3년입니다. 진료일로부터 3년이 지나면 청구가 어려울 수 있으니 가급적 빨리 청구하세요."},{"q":"진단서는 꼭 필요한가요?","a":"소액 외래는 영수증과 세부내역서만으로 가능하지만, 금액이 크거나 질병명 확인이 필요한 경우 진단서를 요구할 수 있습니다."},{"q":"영수증을 잃어버렸어요.","a":"진료받은 병원이나 약국에서 재발급이 가능합니다. 세부내역서도 함께 재발급받아 제출하세요."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('actual-loss', 'silbi-generations-compare', '1~4세대 실손보험 차이 비교 — 내 실손은 어느 세대일까', '판매 시기에 따라 자기부담금과 보장 구조가 다른 1~4세대 실손보험의 핵심 차이를 표로 비교하고, 전환 판단 기준을 정리했습니다.', '<p>실손보험은 판매된 시기에 따라 보장 구조와 자기부담금이 크게 다릅니다. 내가 가입한 실손이 어느 세대인지 알아야 갱신·전환 판단을 제대로 할 수 있습니다.</p>
<h2>세대 구분 한눈에 보기</h2>
<table>
<thead><tr><th>세대</th><th>대략적 판매 시기</th><th>특징</th></tr></thead>
<tbody>
<tr><td>1세대</td><td>2009년 9월 이전</td><td>자기부담금이 거의 없거나 적음, 보장 넓음</td></tr>
<tr><td>2세대</td><td>2009년 10월~2017년 3월</td><td>표준화, 자기부담 10~20% 도입</td></tr>
<tr><td>3세대(착한실손)</td><td>2017년 4월~2021년 6월</td><td>도수치료 등 비급여 일부 특약 분리</td></tr>
<tr><td>4세대</td><td>2021년 7월 이후</td><td>급여·비급여 분리, 비급여 이용량에 따른 할인·할증</td></tr>
</tbody>
</table>
<h2>세대가 올라갈수록 달라진 점</h2>
<ul>
<li>자기부담 비율이 점점 커지는 방향</li>
<li>비급여(도수치료, 주사, MRI 등)가 특약으로 분리</li>
<li>4세대는 비급여를 많이 쓰면 보험료가 할증되고, 안 쓰면 할인</li>
</ul>
<h2>전환을 고민한다면</h2>
<p>오래된 실손은 보장이 넓은 대신 보험료 인상폭이 큰 경향이 있습니다. 반대로 4세대는 보험료가 상대적으로 저렴하지만 자기부담이 늘 수 있습니다. 병원 이용이 적다면 4세대 전환이 유리할 수 있고, 비급여 치료가 잦다면 기존 실손 유지가 나을 수 있습니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>내 실손 세대부터 확인</li><li>병원 이용 빈도가 전환의 핵심 변수</li><li>전환은 되돌리기 어려우니 신중히</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["실손보험","세대비교","4세대실손"]', '[{"q":"내 실손이 몇 세대인지 어떻게 확인하나요?","a":"가입한 보험사 앱이나 증권에서 가입일을 확인하면 세대를 알 수 있습니다. 콜센터에 문의해도 됩니다."},{"q":"4세대로 꼭 바꿔야 하나요?","a":"의무는 아닙니다. 병원 이용이 적으면 보험료가 낮은 4세대가 유리할 수 있지만, 비급여 치료가 잦다면 기존 실손이 나을 수 있습니다."},{"q":"전환하면 다시 돌아올 수 있나요?","a":"일반적으로 이전 세대로 되돌리기는 어렵습니다. 전환 전 보장과 보험료를 충분히 비교하세요."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('actual-loss', 'silbi-non-payment-items', '실손보험 보장 안 되는 항목 — 비급여·면책 정리', '실손보험에서 보장되지 않거나 제한되는 대표 항목(미용·예방·일부 비급여)을 정리해, 청구 전 헛걸음을 줄이는 데 도움을 줍니다.', '<p>실손보험은 "치료 목적의 실제 의료비"를 보장하는 상품입니다. 따라서 치료 목적이 아니거나 약관에서 정한 면책 사유에 해당하면 보장되지 않습니다. 청구 전에 미리 알아두면 헛걸음을 줄일 수 있습니다.</p>
<h2>대표적으로 보장이 어려운 경우</h2>
<ul>
<li>미용·성형 목적 시술(점 제거, 쌍꺼풀 등 외모 개선 목적)</li>
<li>건강검진, 예방접종 등 예방·검진 목적(치료와 무관한 경우)</li>
<li>치과·한방의 일부 비급여(약관에 따라 제한)</li>
<li>간병비, 단순 영양 보충 목적의 주사</li>
</ul>
<h2>비급여는 특약·세대에 따라 다름</h2>
<p>도수치료, 비급여 주사, 비급여 MRI 등은 3·4세대에서 별도 특약으로 분리되어 있고, 자기부담이나 한도가 따로 적용됩니다. 같은 치료라도 가입한 세대와 특약 유무에 따라 결과가 달라집니다.</p>
<h2>치료 목적이면 달라질 수 있다</h2>
<p>외모 개선처럼 보이는 시술도 질병 치료 목적(예: 기능적 문제 해결)이 분명하고 의학적으로 인정되면 보장 대상이 될 수 있습니다. 핵심은 "치료 목적의 의학적 필요성"입니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>미용·예방 목적은 원칙적으로 면책</li><li>비급여는 세대·특약에 따라 천차만별</li><li>치료 목적 입증이 보장의 열쇠</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["실손보험","면책","비급여"]', '[{"q":"도수치료도 실손으로 받을 수 있나요?","a":"치료 목적이면 가능하지만 세대와 특약에 따라 자기부담·한도가 다르고, 횟수가 많으면 추가 자료를 요구할 수 있습니다."},{"q":"건강검진비는 청구되나요?","a":"단순 예방·검진 목적은 원칙적으로 보장되지 않습니다. 다만 검진 중 발견된 질환의 치료비는 보장될 수 있습니다."},{"q":"미용 목적 시술은 전혀 안 되나요?","a":"외모 개선 목적이면 면책이지만, 기능적 문제를 치료하는 의학적 필요성이 인정되면 보장될 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('claim', 'insurance-claim-process-steps', '보험금 청구 절차 — 접수부터 지급까지 단계별 가이드', '사고·질병 발생 후 보험금을 받기까지의 흐름을 접수, 서류 제출, 심사, 지급 4단계로 나눠 설명하고 지연 시 대처법까지 안내합니다.', '<p>보험금 청구는 크게 접수 → 서류 제출 → 심사 → 지급의 흐름으로 진행됩니다. 각 단계에서 무엇이 필요한지 알면 불필요한 지연을 줄일 수 있습니다.</p>
<h2>1단계: 사고·질병 접수</h2>
<p>보험사 앱, 콜센터, 설계사를 통해 사고·진단 사실을 알립니다. 사건 일자, 병원, 진단명 등 기본 정보를 준비하세요.</p>
<h2>2단계: 서류 제출</h2>
<ul>
<li>보험금 청구서, 신분증, 통장 사본(공통)</li>
<li>진단서·입퇴원확인서·영수증·세부내역서 등 보장 항목별 서류</li>
</ul>
<h2>3단계: 심사</h2>
<p>보험사는 제출 서류를 바탕으로 보장 대상 여부와 금액을 확인합니다. 사안에 따라 추가 자료 요청이나 의료자문, 현장 조사가 있을 수 있습니다.</p>
<h2>4단계: 지급</h2>
<p>심사가 끝나면 지정 계좌로 보험금이 지급됩니다. 보험업법상 보험사는 청구 서류 접수 후 정해진 기간 내에 지급하거나, 조사가 필요하면 그 사유와 예상 시점을 안내하도록 되어 있습니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>접수 시 사건 정보를 정확히</li><li>서류는 한 번에 빠짐없이 제출</li><li>지연 시 진행 상황을 서면으로 확인 요청</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["보험금청구","청구절차","보험금지급"]', '[{"q":"보험금은 보통 며칠 만에 나오나요?","a":"서류가 완비되고 단순한 건은 며칠 내 지급되는 경우가 많습니다. 다만 추가 조사나 의료자문이 필요하면 더 걸릴 수 있습니다."},{"q":"청구가 지연되면 어떻게 하나요?","a":"보험사에 진행 상황과 사유를 서면으로 확인 요청할 수 있습니다. 부당한 지연이라면 금융감독원에 민원을 제기할 수도 있습니다."},{"q":"설계사 없이 직접 청구할 수 있나요?","a":"네, 보험사 앱이나 콜센터를 통해 본인이 직접 청구할 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('claim', 'claim-deadline-3-years', '보험금 청구 소멸시효 3년 — 놓치면 못 받는 기한', '보험금청구권의 소멸시효 3년의 의미와 기산점, 시효가 지난 뒤의 대응까지 정리해 청구 누락을 예방하도록 돕습니다.', '<p>보험금을 받을 권리에도 기한이 있습니다. 상법상 보험금청구권의 소멸시효는 원칙적으로 3년이며, 이 기간이 지나면 청구가 어려워질 수 있습니다.</p>
<h2>3년은 언제부터 셀까</h2>
<p>일반적으로 보험금을 청구할 수 있는 사유가 발생한 때(예: 진료일, 진단확정일, 사고일)부터 기산하는 것으로 봅니다. 사안에 따라 기산점 판단이 달라질 수 있어 다툼이 생기기도 합니다.</p>
<h2>과거 진료도 청구 가능</h2>
<ul>
<li>몇 달 전 또는 1~2년 전 진료비도 3년 이내라면 청구할 수 있습니다.</li>
<li>잊고 있던 통원·약제비를 모아 한 번에 청구하는 것도 가능합니다.</li>
</ul>
<h2>시효가 임박했거나 지났다면</h2>
<p>시효가 다가오면 우선 청구서를 접수해 청구 의사를 명확히 남기는 것이 좋습니다. 이미 지났더라도 보험사가 시효를 주장하지 않거나 특별한 사정이 인정되는 경우가 있으므로, 포기하기 전에 전문가 상담을 받아보길 권합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>청구권 시효는 원칙적으로 3년</li><li>기산점은 보통 진료·진단·사고 시점</li><li>임박하면 일단 청구서 접수로 의사 표시</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["보험금청구","소멸시효","청구기한"]', '[{"q":"3년이 지나면 무조건 못 받나요?","a":"원칙적으로 어렵지만, 보험사가 시효를 원용하지 않거나 사정이 인정되는 경우도 있어 전문가 상담을 받아볼 가치가 있습니다."},{"q":"시효는 언제부터 시작되나요?","a":"일반적으로 청구 사유가 발생한 시점(진료일·진단확정일·사고일 등)부터 기산합니다."},{"q":"오래된 진료비도 모아서 청구할 수 있나요?","a":"3년 이내라면 여러 건을 모아 한 번에 청구할 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('claim', 'diagnosis-vs-medical-records', '진단서와 진료기록의 차이 — 청구에 무엇을 낼까', '진단서, 소견서, 진료기록(차트)의 차이와 각 서류가 보험금 청구에서 하는 역할을 비교해, 상황에 맞는 서류 준비를 돕습니다.', '<p>보험금 청구에서 자주 헷갈리는 것이 진단서와 진료기록의 차이입니다. 둘은 용도와 발급 방식이 다르므로 상황에 맞게 준비해야 합니다.</p>
<h2>각 서류의 성격</h2>
<table>
<thead><tr><th>서류</th><th>내용</th><th>비고</th></tr></thead>
<tbody>
<tr><td>진단서</td><td>의사가 확정한 질병명·소견을 담은 공식 문서</td><td>발급 수수료 있음</td></tr>
<tr><td>소견서</td><td>치료 경과·향후 의견 등 의학적 소견</td><td>진단서보다 간단</td></tr>
<tr><td>진료기록(차트)</td><td>진료 경과·검사 결과 등 상세 기록</td><td>사본 발급 가능</td></tr>
</tbody>
</table>
<h2>언제 무엇이 필요할까</h2>
<ul>
<li>질병명·진단 확정이 핵심인 청구(암 진단비 등) → 진단서</li>
<li>소액 통원 → 영수증·세부내역서로 충분한 경우가 많음</li>
<li>보험사 심사에서 경과 확인이 필요할 때 → 진료기록 요청</li>
</ul>
<h2>발급 팁</h2>
<p>진단서는 질병분류기호(KCD 코드)가 기재되도록 요청하면 보장 판단에 도움이 됩니다. 진료기록은 개인정보라 본인 또는 위임받은 사람이 신청해야 합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>진단서 = 확정 진단명, 진료기록 = 상세 경과</li><li>암 등 진단비는 진단서 필수</li><li>질병분류기호 기재 요청이 유리</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["보험금청구","진단서","진료기록"]', '[{"q":"진단서와 소견서 중 무엇을 내야 하나요?","a":"확정 질병명이 필요한 청구는 진단서가 적합합니다. 보험사 안내에 따라 소견서로 갈음되는 경우도 있습니다."},{"q":"진단서에 코드가 꼭 있어야 하나요?","a":"질병분류기호(KCD)가 있으면 보장 판단이 명확해집니다. 발급 시 기재를 요청하세요."},{"q":"진료기록 사본은 누가 뗄 수 있나요?","a":"본인 또는 정당하게 위임받은 사람이 신분 확인을 거쳐 발급받을 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('cancer', 'cancer-diagnosis-benefit-criteria', '암 진단비 지급 기준 — 언제 어떻게 인정될까', '암 진단비가 지급되는 핵심 기준인 조직검사 확정진단과 약관상 암 분류를 설명하고, 진단 시점·서류 준비 요령을 정리했습니다.', '<p>암 진단비는 보험에서 금액이 큰 보장 중 하나라, 지급 기준을 정확히 아는 것이 중요합니다. 핵심은 "약관에서 정한 암으로 확정 진단"되었는지입니다.</p>
<h2>확정 진단의 원칙</h2>
<p>대부분의 약관은 조직검사 등 병리학적 검사로 암이 확진될 것을 요구합니다. 영상검사만으로 암이 의심되는 단계에서는 진단비 지급이 보류될 수 있습니다.</p>
<h2>약관상 암의 분류</h2>
<ul>
<li>일반암: 약관이 정한 일반암 분류에 해당 → 진단비 전액 수준</li>
<li>유사암(소액암): 갑상선암, 경계성종양, 제자리암, 기타 피부암 등 → 일반암보다 적게 지급</li>
</ul>
<table>
<thead><tr><th>구분</th><th>예시</th><th>지급 수준</th></tr></thead>
<tbody>
<tr><td>일반암</td><td>위암·폐암·간암 등</td><td>가입금액 기준 전액 수준</td></tr>
<tr><td>유사암</td><td>갑상선암·제자리암 등</td><td>일부(소액)</td></tr>
</tbody>
</table>
<h2>진단 시점과 보장 개시</h2>
<p>암 진단비는 보통 가입 후 일정 기간(면책기간)이 지난 뒤 확정 진단되어야 보장됩니다. 진단확정일이 보장 개시 이후인지 확인이 필요합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>조직검사 확진이 원칙</li><li>유사암은 소액 지급</li><li>면책기간과 진단확정일 확인 필수</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["암보험","암진단비","진단확정"]', '[{"q":"영상검사에서 암이 의심되면 진단비가 나오나요?","a":"대개 조직검사 등으로 확정 진단되어야 지급됩니다. 의심 단계에서는 보류될 수 있습니다."},{"q":"갑상선암도 일반암 진단비를 받나요?","a":"많은 약관에서 갑상선암은 유사암(소액암)으로 분류되어 일반암보다 적게 지급됩니다. 약관을 확인하세요."},{"q":"가입하자마자 진단받으면 보장되나요?","a":"암 진단비는 보통 가입 후 면책기간이 지난 뒤 확정 진단되어야 보장됩니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('cancer', 'minor-cancer-vs-general-cancer', '유사암·소액암과 일반암의 차이 — 보장 금액이 갈리는 이유', '갑상선암·제자리암·경계성종양 등 유사암이 일반암과 어떻게 다르게 보장되는지, 가입 전 확인할 점을 정리했습니다.', '<p>암보험에서 "암 진단비 OO만원"이라고 해도 모든 암에 같은 금액이 나오는 것은 아닙니다. 유사암(소액암)으로 분류되면 일반암보다 적게 지급됩니다.</p>
<h2>유사암으로 분류되는 대표 항목</h2>
<ul>
<li>갑상선암</li>
<li>제자리암(상피내암)</li>
<li>경계성종양</li>
<li>기타 피부암</li>
</ul>
<h2>왜 금액이 다를까</h2>
<p>이들은 상대적으로 치료 예후가 좋거나 진행 정도가 초기인 경우가 많아, 보험에서 일반암과 구분해 소액으로 보장하도록 설계되어 있습니다. 보험료 부담을 낮추는 대신 보장 금액을 차등화한 구조입니다.</p>
<h2>가입 전 확인할 점</h2>
<table>
<thead><tr><th>확인 항목</th><th>이유</th></tr></thead>
<tbody>
<tr><td>유사암 보장 금액</td><td>일반암 대비 몇 % 수준인지</td></tr>
<tr><td>유사암 별도 특약</td><td>유사암 보장을 키울 수 있는지</td></tr>
<tr><td>분류 기준</td><td>약관이 정한 코드·범위</td></tr>
</tbody>
</table>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>유사암은 일반암보다 적게 지급</li><li>대표 항목: 갑상선암·제자리암·경계성종양</li><li>유사암 보장 비율을 가입 전 확인</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["암보험","유사암","소액암"]', '[{"q":"유사암은 진단비가 얼마나 나오나요?","a":"상품마다 다르지만 일반암 가입금액의 일부 수준으로 지급되는 경우가 많습니다. 약관의 지급비율을 확인하세요."},{"q":"제자리암도 암 진단비 대상인가요?","a":"대개 유사암(소액암)으로 분류되어 소액이 지급됩니다. 일반암 진단비와는 금액이 다릅니다."},{"q":"유사암 보장을 늘릴 수 있나요?","a":"유사암 진단비를 별도 특약으로 추가하거나 가입금액을 조정해 보장을 키울 수 있는 상품도 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('cancer', 'cancer-renewal-vs-nonrenewal', '갱신형 vs 비갱신형 암보험 — 무엇이 유리할까', '갱신형과 비갱신형 암보험의 보험료 구조 차이를 비교하고, 연령·가입기간에 따른 선택 기준을 정리했습니다.', '<p>암보험을 고를 때 자주 마주치는 선택지가 갱신형과 비갱신형입니다. 보험료가 오르는 방식이 달라 장기적인 부담이 크게 차이날 수 있습니다.</p>
<h2>두 방식의 차이</h2>
<table>
<thead><tr><th>구분</th><th>갱신형</th><th>비갱신형</th></tr></thead>
<tbody>
<tr><td>초기 보험료</td><td>상대적으로 저렴</td><td>상대적으로 높음</td></tr>
<tr><td>이후 보험료</td><td>갱신마다 인상 가능</td><td>납입기간 동안 고정</td></tr>
<tr><td>장기 부담</td><td>나이 들수록 커질 수 있음</td><td>예측 가능</td></tr>
</tbody>
</table>
<h2>갱신형이 맞는 경우</h2>
<ul>
<li>당장 보험료 부담을 낮추고 싶을 때</li>
<li>짧은 기간만 보장이 필요할 때</li>
</ul>
<h2>비갱신형이 맞는 경우</h2>
<ul>
<li>장기간 안정적으로 보장을 유지하고 싶을 때</li>
<li>은퇴 후 보험료 인상이 부담스러울 때</li>
</ul>
<p>젊을 때 가입해 오래 유지할 계획이라면 비갱신형이 총부담 면에서 유리한 경우가 많고, 단기·저렴함이 우선이면 갱신형을 고려할 수 있습니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>갱신형=초기 저렴·이후 인상</li><li>비갱신형=초기 부담·이후 고정</li><li>유지 기간과 은퇴 후 부담을 기준으로 판단</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["암보험","갱신형","비갱신형"]', '[{"q":"갱신형은 보험료가 얼마나 오르나요?","a":"갱신 시점의 연령·위험률에 따라 달라집니다. 나이가 들수록 인상폭이 커지는 경향이 있습니다."},{"q":"비갱신형은 평생 보험료가 같나요?","a":"납입기간 동안 보험료가 고정됩니다. 다만 납입 완료 후에도 보장이 유지되는지는 상품 구조를 확인하세요."},{"q":"둘을 섞을 수도 있나요?","a":"주계약은 비갱신, 일부 특약은 갱신형으로 구성되는 상품도 많습니다. 설계 시 조합을 조정할 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('car', 'car-fault-ratio-basics', '자동차보험 과실비율 — 어떻게 정해질까', '과실비율의 산정 원리와 기본과실·수정요소, 분쟁 시 활용할 수 있는 과실비율분쟁심의위원회까지 정리했습니다.', '<p>교통사고가 나면 손해를 누가 얼마나 부담할지 정하는 것이 과실비율입니다. 과실비율에 따라 보험금과 향후 보험료 할증이 달라지므로 산정 원리를 알아둘 필요가 있습니다.</p>
<h2>기본과실 + 수정요소</h2>
<p>과실비율은 사고 유형별 기본과실에서 출발해, 구체적인 사정(신호 위반, 속도, 보행자 보호 등)을 가감해 최종 비율을 정합니다. 손해보험협회의 과실비율 인정기준이 널리 참고됩니다.</p>
<h2>과실비율이 미치는 영향</h2>
<ul>
<li>상대방·내 차 손해의 분담 비율 결정</li>
<li>내 보험 사용 여부와 할증에 영향</li>
<li>대인·대물 보상 범위에 반영</li>
</ul>
<h2>다툼이 있을 때</h2>
<p>보험사 간 과실비율에 합의가 안 되면 과실비율분쟁심의위원회의 심의를 통해 조정받을 수 있습니다. 블랙박스 영상, 사고 현장 사진, 목격자 진술 등 객관적 자료가 결정적입니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>기본과실에 수정요소를 가감</li><li>블랙박스·현장 자료가 핵심 증거</li><li>합의 불가 시 분쟁심의위원회 활용</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["자동차보험","과실비율","교통사고"]', '[{"q":"과실비율은 누가 정하나요?","a":"1차적으로 양측 보험사가 협의하며, 손해보험협회의 인정기준을 참고합니다. 합의가 안 되면 분쟁심의위원회나 소송으로 갑니다."},{"q":"블랙박스가 없으면 불리한가요?","a":"객관적 증거가 적으면 기본과실 위주로 판단되어 불리할 수 있습니다. 현장 사진·목격자 확보가 중요합니다."},{"q":"과실이 적어도 보험료가 오르나요?","a":"내 보험으로 보험금을 지급하면 과실이 적어도 할증 요인이 될 수 있습니다. 소액은 자비 처리가 유리할 때도 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('car', 'car-discount-surcharge-system', '자동차보험 할인할증등급 — 사고 나면 얼마나 오를까', '무사고 할인과 사고 시 할증이 작동하는 할인할증등급·사고점수 구조를 설명하고, 물적사고 할증기준금액의 의미를 정리했습니다.', '<p>자동차보험료는 사고 이력에 따라 오르내립니다. 그 핵심이 할인할증등급과 사고점수 제도입니다. 무사고가 쌓이면 할인, 사고가 나면 할증이 적용됩니다.</p>
<h2>무사고 할인</h2>
<p>일반적으로 1년간 사고가 없으면 등급이 올라 보험료가 할인되는 방향으로 작동합니다. 장기 무사고일수록 할인 폭이 커집니다.</p>
<h2>사고 시 할증</h2>
<ul>
<li>대인·대물·자기신체 사고 등은 사고 내용에 따라 점수가 부여됩니다.</li>
<li>점수가 쌓이면 등급이 내려가 보험료가 할증됩니다.</li>
</ul>
<h2>물적사고 할증기준금액</h2>
<p>가입 시 정하는 물적사고 할증기준금액(예: 50/100/150/200만원)보다 작은 손해는 할증 점수가 낮게 적용될 수 있습니다. 다만 사고 건수 자체가 향후 보험료에 영향을 줄 수 있으니, 소액 사고는 자비 처리가 유리한지 따져볼 필요가 있습니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>1년 무사고면 할인 방향</li><li>사고는 점수로 환산되어 할증</li><li>소액 사고는 자비 처리 손익 비교</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["자동차보험","할인할증","보험료"]', '[{"q":"사고 한 번에 보험료가 얼마나 오르나요?","a":"사고 내용·점수·기존 등급에 따라 다릅니다. 대물 소액 사고와 대인 사고는 할증 영향이 크게 다릅니다."},{"q":"물적사고 할증기준금액은 무엇인가요?","a":"이 금액 이하의 물적 손해는 할증 점수가 낮게 적용될 수 있는 기준선입니다. 가입 시 선택합니다."},{"q":"소액 사고는 보험 처리를 안 하는 게 낫나요?","a":"수리비가 적다면 할증으로 인한 향후 보험료 증가와 비교해 자비 처리가 유리할 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('practice', 'first-consultation-checklist', '초회 상담 체크리스트 — 첫 만남에서 챙길 것들', '보험설계사의 초회 상담에서 신뢰를 쌓고 니즈를 파악하기 위한 준비물과 대화 흐름, 컴플라이언스 유의점을 정리했습니다.', '<p>초회 상담은 고객과의 신뢰가 시작되는 자리입니다. 상품을 파는 자리가 아니라 고객의 상황과 니즈를 이해하는 자리로 접근할 때 계약과 유지가 모두 좋아집니다.</p>
<h2>상담 전 준비</h2>
<ul>
<li>고객 기본 정보(가족·직업·기존 보험) 사전 파악</li>
<li>상담 도구(니즈 분석표, 보장 분석 자료)</li>
<li>본인 신분·소속을 밝힐 수 있는 자료</li>
</ul>
<h2>상담 중 대화 흐름</h2>
<table>
<thead><tr><th>단계</th><th>핵심</th></tr></thead>
<tbody>
<tr><td>라포 형성</td><td>경청, 고객의 관심사부터</td></tr>
<tr><td>니즈 환기</td><td>현재 보장의 빈틈 함께 확인</td></tr>
<tr><td>정보 정리</td><td>우선순위·예산 합의</td></tr>
<tr><td>다음 약속</td><td>구체적 제안은 다음 만남으로</td></tr>
</tbody>
</table>
<h2>컴플라이언스 유의</h2>
<p>설명의무, 적합성 원칙을 지키고 과장·단정적 표현을 피해야 합니다. 청약철회(보통 15일)와 품질보증해지 등 소비자 권리도 정확히 안내하는 것이 장기 신뢰에 도움이 됩니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>판매보다 니즈 파악 우선</li><li>대화는 경청 → 니즈환기 → 정리 순</li><li>설명의무·소비자 권리 정확히 안내</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["설계사실무","상담","리쿠르팅"]', '[{"q":"초회 상담에서 바로 상품을 권해도 되나요?","a":"니즈 파악이 먼저입니다. 첫 만남은 정보 수집과 신뢰 형성에 집중하고, 구체 제안은 다음 만남으로 넘기는 것이 효과적입니다."},{"q":"청약철회 기간은 얼마인가요?","a":"일반적으로 청약일로부터 일정 기간(흔히 15일) 내 철회가 가능합니다. 상품·조건에 따라 다를 수 있어 정확히 안내해야 합니다."},{"q":"상담 시 꼭 지켜야 할 것은?","a":"설명의무와 적합성 원칙을 지키고 단정적·과장 표현을 피하며, 소비자 권리를 정확히 안내해야 합니다."}]', 'published', 'InsureConnect 편집팀');
